import React, { useState } from "react";
import axios from "axios";
import {
    Typography,
    TextField,
    Button,
    Paper,
    Box,
    Chip,
    Stack,
} from "@mui/material";
import AddCircleOutlineIcon from "@mui/icons-material/AddCircleOutline";
import { useNavigate } from "react-router-dom";

const initial = {
    postId: "",
    postProfile: "",
    reqExperience: 0,
    postTechStack: [],
    postDesc: "",
};

const Create = () => {
    const skillSet = [
        "JavaScript",
        "Java",
        "Python",
        "Django",
        "Rust",
        "React",
        "Spring",
        "SQL",
    ];

    const navigate = useNavigate();
    const [form, setForm] = useState(initial);

    const handleSubmit = (e) => {
        e.preventDefault();

        axios
            .post("http://localhost:8080/jobPost", form)
            .then((resp) => {
                console.log(resp.data);
                navigate("/");
            })
            .catch((error) => {
                console.log(error);
            });
    };

    const toggleSkill = (skill) => {
        if (form.postTechStack.includes(skill)) {
            setForm({
                ...form,
                postTechStack: form.postTechStack.filter(
                    (s) => s !== skill
                ),
            });
        } else {
            setForm({
                ...form,
                postTechStack: [...form.postTechStack, skill],
            });
        }
    };

    return (
        <Box
            sx={{
                minHeight: "100vh",
                background:
                    "linear-gradient(to right,#f8fafc,#e2e8f0)",
                p: 4,
            }}
        >
            <Paper
                elevation={10}
                sx={{
                    maxWidth: 850,
                    mx: "auto",
                    p: 5,
                    borderRadius: 5,
                    background: "#ffffff",
                }}
            >
                <Typography
                    variant="h4"
                    sx={{
                        fontWeight: 700,
                        textAlign: "center",
                        mb: 4,
                        color: "#0f172a",
                    }}
                >
                    Create New Job Post
                </Typography>

                <form onSubmit={handleSubmit}>
                    <TextField
                        fullWidth
                        label="Post ID"
                        type="number"
                        sx={{ mb: 3 }}
                        value={form.postId}
                        onChange={(e) =>
                            setForm({
                                ...form,
                                postId: e.target.value,
                            })
                        }
                    />

                    <TextField
                        fullWidth
                        label="Job Profile"
                        sx={{ mb: 3 }}
                        value={form.postProfile}
                        onChange={(e) =>
                            setForm({
                                ...form,
                                postProfile: e.target.value,
                            })
                        }
                    />

                    <TextField
                        fullWidth
                        label="Years of Experience"
                        type="number"
                        sx={{ mb: 3 }}
                        value={form.reqExperience}
                        onChange={(e) =>
                            setForm({
                                ...form,
                                reqExperience: e.target.value,
                            })
                        }
                    />

                    <TextField
                        fullWidth
                        multiline
                        rows={5}
                        label="Job Description"
                        sx={{ mb: 4 }}
                        value={form.postDesc}
                        onChange={(e) =>
                            setForm({
                                ...form,
                                postDesc: e.target.value,
                            })
                        }
                    />

                    <Typography
                        variant="h6"
                        sx={{
                            fontWeight: 600,
                            mb: 2,
                        }}
                    >
                        Required Skills
                    </Typography>

                    <Stack
                        direction="row"
                        spacing={1}
                        flexWrap="wrap"
                        sx={{ mb: 4 }}
                    >
                        {skillSet.map((skill) => (
                            <Chip
                                key={skill}
                                label={skill}
                                clickable
                                color={
                                    form.postTechStack.includes(skill)
                                        ? "primary"
                                        : "default"
                                }
                                onClick={() => toggleSkill(skill)}
                                sx={{
                                    mb: 1,
                                    fontSize: "15px",
                                }}
                            />
                        ))}
                    </Stack>

                    <Button
                        fullWidth
                        size="large"
                        variant="contained"
                        startIcon={<AddCircleOutlineIcon />}
                        type="submit"
                        sx={{
                            py: 1.8,
                            borderRadius: 3,
                            fontSize: "16px",
                            fontWeight: 700,
                            textTransform: "none",
                            background:
                                "linear-gradient(90deg,#2563eb,#06b6d4)",
                        }}
                    >
                        Create Job Post
                    </Button>
                </form>
            </Paper>
        </Box>
    );
};

export default Create;
